#include <stdio.h>
#include <stdint.h>
#include <string.h>

/*
 * Block Cipher Design Principles - C Implementation
 * Demonstrates SPN structure with S-Boxes, P-Boxes, and Key Schedule
 */

#define BLOCK_SIZE 16   /* 16 bits for demonstration */
#define NUM_ROUNDS 4
#define SBOX_SIZE 256

/* Global S-Box and P-Box */
uint8_t sbox[SBOX_SIZE];
uint8_t pbox[BLOCK_SIZE];

/* Function prototypes */
void generate_sbox(void);
void generate_pbox(void);
uint16_t sub_bytes(uint16_t state);
uint16_t permute_bits(uint16_t state);
uint16_t key_mix(uint16_t state, uint32_t round_key);
void generate_round_keys(uint32_t master_key, uint32_t* round_keys);
uint16_t encrypt_block(uint16_t plaintext, uint32_t* round_keys);
uint16_t decrypt_block(uint16_t ciphertext, uint32_t* round_keys);

/* Generate non-linear S-Box using affine transformation */
void generate_sbox(void) {
    for (int i = 0; i < SBOX_SIZE; i++) {
        uint8_t inv = (i == 0) ? 0 : (uint8_t)(~i + 1); /* Simple inverse */

        /* Affine transformation for non-linearity */
        uint8_t b = inv;
        b = ((b << 1) | (b >> 7)) & 0xFF;  /* Rotate left */
        b = b ^ 0x63;  /* XOR with constant 0x63 */

        sbox[i] = b;
    }
}

/* Generate P-Box for bit diffusion */
void generate_pbox(void) {
    /* Simple but effective permutation pattern */
    int pattern[] = {0, 4, 8, 12, 1, 5, 9, 13, 2, 6, 10, 14, 3, 7, 11, 15};
    for (int i = 0; i < BLOCK_SIZE; i++) {
        pbox[i] = pattern[i];
    }
}

/* Apply S-Box substitution to each byte of the state */
uint16_t sub_bytes(uint16_t state) {
    uint16_t result = 0;

    /* Process each byte */
    for (int i = 0; i < 2; i++) {
        uint8_t byte = (state >> (i * 8)) & 0xFF;
        uint8_t substituted = sbox[byte];
        result |= ((uint16_t)substituted << (i * 8));
    }

    return result;
}

/* Apply P-Box permutation for bit diffusion */
uint16_t permute_bits(uint16_t state) {
    uint16_t result = 0;

    for (int i = 0; i < BLOCK_SIZE; i++) {
        if ((state >> i) & 1) {
            result |= (1 << pbox[i]);
        }
    }

    return result;
}

/* XOR state with round key (key mixing) */
uint16_t key_mix(uint16_t state, uint32_t round_key) {
    /* Use lower 16 bits of round key */
    return state ^ (round_key & 0xFFFF);
}

/* Generate round keys from master key using key schedule */
void generate_round_keys(uint32_t master_key, uint32_t* round_keys) {
    uint32_t key = master_key;

    for (int round = 0; round <= NUM_ROUNDS; round++) {
        round_keys[round] = key;

        /* Key schedule: rotate, substitute, mix */
        key = ((key << 1) | (key >> 31)) & 0xFFFFFFFF;

        /* Simple S-Box application to parts of key */
        uint8_t byte1 = (key >> 24) & 0xFF;
        uint8_t byte2 = (key >> 16) & 0xFF;
        key = ((uint32_t)sbox[byte1] << 24) | ((uint32_t)sbox[byte2] << 16) |
              (key & 0xFFFF);

        /* XOR with round constant */
        key ^= (0x01000000 * round);
    }
}

/* Encrypt a single block using SPN structure */
uint16_t encrypt_block(uint16_t plaintext, uint32_t* round_keys) {
    uint16_t state = plaintext;

    /* Initial key mixing (whitening) */
    state = key_mix(state, round_keys[0]);

    /* Main rounds: SubBytes -> Permute -> KeyMix */
    for (int round = 1; round < NUM_ROUNDS; round++) {
        state = sub_bytes(state);      /* Substitution (confusion) */
        state = permute_bits(state);    /* Permutation (diffusion) */
        state = key_mix(state, round_keys[round]);  /* Key mixing */
    }

    /* Final round (no permutation for efficiency) */
    state = sub_bytes(state);
    state = key_mix(state, round_keys[NUM_ROUNDS]);

    return state;
}

/* Decrypt a single block (reverse of encryption) */
uint16_t decrypt_block(uint16_t ciphertext, uint32_t* round_keys) {
    uint16_t state = ciphertext;

    /* Initial key mixing */
    state = key_mix(state, round_keys[NUM_ROUNDS]);

    /* Reverse final round */
    /* Note: In production, use inverse S-Box */
    state = sub_bytes(state);

    /* Reverse main rounds */
    for (int round = NUM_ROUNDS - 1; round >= 1; round--) {
        state = key_mix(state, round_keys[round]);
        /* In production: inverse permute, inverse sub bytes */
        state = permute_bits(state);    /* Simplified: same permutation */
        state = sub_bytes(state);       /* In production: inverse S-Box */
    }

    /* Final XOR */
    state = key_mix(state, round_keys[0]);

    return state;
}

/* Print binary representation for visualization */
void print_binary(uint16_t value) {
    for (int i = 15; i >= 0; i--) {
        printf("%d", (value >> i) & 1);
        if (i % 4 == 0) printf(" ");
    }
}

/* Main demonstration */
int main(void) {
    /* Initialize cipher components */
    generate_sbox();
    generate_pbox();

    /* Test values */
    uint16_t plaintext = 0x1234;
    uint32_t master_key = 0xDEADBEEF;
    uint32_t round_keys[NUM_ROUNDS + 1];

    /* Generate round keys */
    generate_round_keys(master_key, round_keys);

    printf("Block Cipher - SPN Design Principles\n");
    printf("======================================\n\n");

    printf("Plaintext:  0x%04X\n", plaintext);
    printf("Master Key: 0x%08X\n\n", master_key);

    /* Display S-Box sample */
    printf("S-Box Sample (hex):\n");
    for (int i = 0; i < 16; i++) {
        printf("%02X ", sbox[i]);
    }
    printf("\n\n");

    /* Display P-Box */
    printf("P-Box (input->output):\n");
    for (int i = 0; i < BLOCK_SIZE; i++) {
        printf("%d->%d ", i, pbox[i]);
    }
    printf("\n\n");

    /* Display round keys */
    printf("Round Keys:\n");
    for (int i = 0; i <= NUM_ROUNDS; i++) {
        printf("  Round %d: 0x%08X\n", i, round_keys[i]);
    }
    printf("\n");

    /* Encryption */
    uint16_t ciphertext = encrypt_block(plaintext, round_keys);
    printf("Ciphertext: 0x%04X\n", ciphertext);

    /* Decryption */
    uint16_t decrypted = decrypt_block(ciphertext, round_keys);
    printf("Decrypted:  0x%04X\n\n", decrypted);

    /* Visualize transformation */
    printf("Binary Transformation:\n");
    printf("Plaintext:  ");
    print_binary(plaintext);
    printf("\nCiphertext: ");
    print_binary(ciphertext);
    printf("\n");

    /* Verification */
    printf("\nVerification: %s\n", 
           (plaintext == decrypted) ? "SUCCESS - Encryption/Decryption working" 
                                   : "FAILED");

    return 0;
}
